<?php
if(session_status()===PHP_SESSION_NONE)session_start();
include "../../inc/config.php";
session_check_json();
function fcj($s,$m='',$x=array()){header('Content-Type: application/json');$p=array('status'=>$s);if($m!=='')$p['error_message']=$m;foreach($x as $k=>$v)$p[$k]=$v;echo json_encode($p);exit;}
function fch($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
function fcq($v){return (float)str_replace(',','.',trim((string)$v));}
function fc_get($k,$d=''){return isset($_POST[$k])?$_POST[$k]:$d;}
function fc_next_no(){global $db;$prefix='FC'.date('Y');$r=$db->fetch("SELECT calendar_code FROM erp_factory_calendar_header WHERE calendar_code LIKE ? ORDER BY calendar_code DESC LIMIT 1",array($prefix.'%'));$n=1;if($r&&preg_match('/(\d{4})$/',$r->calendar_code,$m))$n=(int)$m[1]+1;return $prefix.sprintf('%04d',$n);}
function fc_filters_get(){return array('from'=>isset($_GET['tgl_awal'])&&$_GET['tgl_awal']!==''?$_GET['tgl_awal']:date('Y-01-01'),'to'=>isset($_GET['tgl_akhir'])&&$_GET['tgl_akhir']!==''?$_GET['tgl_akhir']:date('Y-12-31'),'status'=>isset($_GET['status'])?trim($_GET['status']):'','plant'=>isset($_GET['plant'])?trim($_GET['plant']):'','keyword'=>isset($_GET['keyword'])?trim($_GET['keyword']):'');}
function fc_where($f,&$p){$w=" WHERE h.valid_from<=? AND h.valid_to>=? ";$p[]=$f['to'];$p[]=$f['from'];if($f['status']!==''){$w.=" AND h.calendar_status=? ";$p[]=$f['status'];}if($f['plant']!==''){$w.=" AND h.plant_code=? ";$p[]=$f['plant'];}if($f['keyword']!==''){$kw='%'.$f['keyword'].'%';$w.=" AND (h.calendar_code LIKE ? OR h.calendar_name LIKE ? OR h.plant_code LIKE ? OR h.default_shift_code LIKE ?) ";for($i=0;$i<4;$i++)$p[]=$kw;}return $w;}
function fc_day_name($date){$names=array(1=>'Minggu',2=>'Senin',3=>'Selasa',4=>'Rabu',5=>'Kamis',6=>'Jumat',7=>'Sabtu');return $names[(int)date('w',strtotime($date))+1];}
function fc_generate_days($header){
  global $db,$username;
  $map=array(1=>'sunday',2=>'monday',3=>'tuesday',4=>'wednesday',5=>'thursday',6=>'friday',7=>'saturday');
  $start=strtotime($header->valid_from);$end=strtotime($header->valid_to);$count=0;
  for($t=$start;$t<=$end;$t=strtotime('+1 day',$t)){
    $date=date('Y-m-d',$t);$dow=(int)date('w',$t)+1;$field=$map[$dow];$isWork=$header->$field==='Y';$tipe=$isWork?'Kerja':'Libur';$hours=$isWork?(float)$header->working_hours:0;
    $exist=$db->fetch("SELECT id,source_type FROM erp_factory_calendar WHERE calendar_id=? AND tanggal=? LIMIT 1",array($header->id,$date));
    $shiftId=$isWork?$header->default_shift_id:null;$shiftCode=$isWork?$header->default_shift_code:null;$ket=$isWork?'Generated working day':'Generated non-working day';$now=date('Y-m-d H:i:s');
    if($exist){
      if($exist->source_type==='EXCEPTION')continue;
      $db->query("UPDATE erp_factory_calendar SET calendar_code=?,plant_id=?,plant_code=?,nama_hari=?,weekday_no=?,tipe_hari=?,shift_id=?,shift_code=?,working_hours=?,keterangan=?,source_type='GENERATED',updated_by=?,updated_at=? WHERE id=?",array($header->calendar_code,$header->plant_id,$header->plant_code,fc_day_name($date),$dow,$tipe,$shiftId,$shiftCode,$hours,$ket,$username,$now,$exist->id));
    }else{
      $db->query("INSERT INTO erp_factory_calendar (calendar_id,calendar_code,plant_id,plant_code,tanggal,nama_hari,weekday_no,tipe_hari,shift_id,shift_code,working_hours,keterangan,source_type,updated_by,updated_at) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)",array($header->id,$header->calendar_code,$header->plant_id,$header->plant_code,$date,fc_day_name($date),$dow,$tipe,$shiftId,$shiftCode,$hours,$ket,'GENERATED',$username,$now));
    }
    $count++;
  }
  $db->query("UPDATE erp_factory_calendar SET working_hours=0,shift_id=NULL,shift_code=NULL WHERE calendar_id=? AND tipe_hari<>'Kerja' AND source_type<>'EXCEPTION'",array($header->id));
  return $count;
}
$act=isset($_GET['act'])?$_GET['act']:'';$username=isset($_SESSION['username'])?$_SESSION['username']:'system';
switch($act){
  case 'next_no':fcj('good','',array('calendar_code'=>fc_next_no()));break;
  case 'get':
    $id=(int)fc_get('id');$h=$db->fetch("SELECT * FROM erp_factory_calendar_header WHERE id=? LIMIT 1",array($id));if(!$h)fcj('error','Factory Calendar tidak ditemukan.');fcj('good','',array('header'=>(array)$h));break;
  case 'save':
    $id=(int)fc_get('id');$name=trim(fc_get('calendar_name'));$plantId=fc_get('plant_id')!==''?(int)fc_get('plant_id'):null;$plant=trim(fc_get('plant_code'));$from=trim(fc_get('valid_from'));$to=trim(fc_get('valid_to'));$shiftId=fc_get('default_shift_id')!==''?(int)fc_get('default_shift_id'):null;$shiftCode=trim(fc_get('default_shift_code'));$hours=fcq(fc_get('working_hours',8));
    if($name==='')fcj('error','Calendar Name wajib diisi.');if($plant==='')fcj('error','Plant wajib dipilih.');if($from===''||$to==='')fcj('error','Valid From dan Valid To wajib diisi.');if(strtotime($to)<strtotime($from))fcj('error','Valid To tidak boleh sebelum Valid From.');if($hours<=0)fcj('error','Working Hours wajib lebih dari 0.');
    $plantRow=$db->fetch("SELECT id,plant_code FROM erp_plant WHERE plant_code=? LIMIT 1",array($plant));if(!$plantRow)fcj('error','Plant tidak ditemukan.');
    $shift=$shiftCode!==''?$db->fetch("SELECT id,kode_shift FROM erp_shift WHERE kode_shift=? AND status='Aktif' LIMIT 1",array($shiftCode)):null;if($shift){$shiftId=$shift->id;$shiftCode=$shift->kode_shift;}
    $data=array('calendar_name'=>$name,'plant_id'=>$plantId?:$plantRow->id,'plant_code'=>$plant,'valid_from'=>$from,'valid_to'=>$to,'monday'=>fc_get('monday')==='Y'?'Y':'N','tuesday'=>fc_get('tuesday')==='Y'?'Y':'N','wednesday'=>fc_get('wednesday')==='Y'?'Y':'N','thursday'=>fc_get('thursday')==='Y'?'Y':'N','friday'=>fc_get('friday')==='Y'?'Y':'N','saturday'=>fc_get('saturday')==='Y'?'Y':'N','sunday'=>fc_get('sunday')==='Y'?'Y':'N','default_shift_id'=>$shiftId,'default_shift_code'=>$shiftCode,'working_hours'=>$hours,'remarks'=>fc_get('remarks'),'updated_by'=>$username,'updated_at'=>date('Y-m-d H:i:s'));
    $db->query('START TRANSACTION');
    if($id>0){$old=$db->fetch("SELECT * FROM erp_factory_calendar_header WHERE id=? LIMIT 1",array($id));if(!$old){$db->query('ROLLBACK');fcj('error','Factory Calendar tidak ditemukan.');}if($old->calendar_status!=='DRAFT'){$db->query('ROLLBACK');fcj('error','Hanya kalender DRAFT yang bisa diedit.');}$code=$old->calendar_code;$ok=$db->update('erp_factory_calendar_header',$data,'id',$id);}
    else{$code=fc_next_no();$data['calendar_code']=$code;$data['calendar_status']='DRAFT';$data['created_by']=$username;$ok=$db->insert('erp_factory_calendar_header',$data);$id=$db->last_insert_id();}
    if(!$ok){$e=$db->getErrorMessage();$db->query('ROLLBACK');fcj('error',$e?:'Factory Calendar gagal disimpan.');}
    $h=$db->fetch("SELECT * FROM erp_factory_calendar_header WHERE id=? LIMIT 1",array($id));$generated=fc_generate_days($h);
    if(function_exists('simpan_log'))simpan_log('User '.$username.' menyimpan Factory Calendar '.$code.' dan generate '.$generated.' hari pada '.date('Y-m-d H:i:s'),$username);$db->query('COMMIT');fcj('good','',array('id'=>$id,'calendar_code'=>$code,'generated'=>$generated));break;
  case 'generate':
    $id=(int)fc_get('id');$h=$db->fetch("SELECT * FROM erp_factory_calendar_header WHERE id=? LIMIT 1",array($id));if(!$h)fcj('error','Factory Calendar tidak ditemukan.');$count=fc_generate_days($h);if(function_exists('simpan_log'))simpan_log('User '.$username.' generate ulang Factory Calendar '.$h->calendar_code.' sebanyak '.$count.' hari',$username);fcj('good','',array('generated'=>$count));break;
  case 'release':
    $id=(int)fc_get('id');$h=$db->fetch("SELECT * FROM erp_factory_calendar_header WHERE id=? LIMIT 1",array($id));if(!$h)fcj('error','Factory Calendar tidak ditemukan.');if($h->calendar_status!=='DRAFT')fcj('error','Hanya DRAFT yang bisa release.');$cnt=$db->fetch("SELECT COUNT(*) jml FROM erp_factory_calendar WHERE calendar_id=?",array($id));if(!$cnt||(int)$cnt->jml<=0)fcj('error','Generate calendar days terlebih dahulu.');$db->query("UPDATE erp_factory_calendar_header SET calendar_status='RELEASED',released_by=?,released_at=NOW(),updated_by=?,updated_at=NOW() WHERE id=?",array($username,$username,$id));if(function_exists('simpan_log'))simpan_log('User '.$username.' release Factory Calendar '.$h->calendar_code,$username);fcj('good');break;
  case 'inactive':
    $id=(int)fc_get('id');$reason=trim(fc_get('reason'));if($reason==='')fcj('error','Reason inactive wajib diisi.');$h=$db->fetch("SELECT * FROM erp_factory_calendar_header WHERE id=? LIMIT 1",array($id));if(!$h)fcj('error','Factory Calendar tidak ditemukan.');if($h->calendar_status!=='RELEASED')fcj('error','Hanya RELEASED yang bisa inactive.');$db->query("UPDATE erp_factory_calendar_header SET calendar_status='INACTIVE',inactive_reason=?,updated_by=?,updated_at=NOW() WHERE id=?",array($reason,$username,$id));if(function_exists('simpan_log'))simpan_log('User '.$username.' inactive Factory Calendar '.$h->calendar_code.' alasan '.$reason,$username);fcj('good');break;
  case 'delete':
    $id=(int)fc_get('id');$h=$db->fetch("SELECT * FROM erp_factory_calendar_header WHERE id=? LIMIT 1",array($id));if(!$h)fcj('error','Factory Calendar tidak ditemukan.');if($h->calendar_status!=='DRAFT')fcj('error','Hanya DRAFT yang bisa delete.');$db->query('START TRANSACTION');$db->query("DELETE FROM erp_factory_calendar WHERE calendar_id=?",array($id));$db->delete('erp_factory_calendar_header','id',$id);$db->query('COMMIT');if(function_exists('simpan_log'))simpan_log('User '.$username.' delete draft Factory Calendar '.$h->calendar_code,$username);fcj('good');break;
  case 'update_day':
    $id=(int)fc_get('day_id');$tipe=fc_get('tipe_hari','Kerja');$shiftCode=trim(fc_get('shift_code'));$hours=fcq(fc_get('working_hours',0));$ket=fc_get('keterangan');if(!in_array($tipe,array('Kerja','Libur','Khusus'),true))fcj('error','Tipe hari tidak valid.');if($tipe==='Kerja'&&$hours<=0)$hours=8;if($tipe==='Libur'){$shiftCode='';$hours=0;}$shift=$shiftCode!==''?$db->fetch("SELECT id,kode_shift FROM erp_shift WHERE kode_shift=? LIMIT 1",array($shiftCode)):null;$db->update('erp_factory_calendar',array('tipe_hari'=>$tipe,'shift_id'=>$shift?$shift->id:null,'shift_code'=>$shift?$shift->kode_shift:null,'working_hours'=>$hours,'exception_type'=>$tipe==='Kerja'?null:'MANUAL','source_type'=>'EXCEPTION','keterangan'=>$ket,'updated_by'=>$username,'updated_at'=>date('Y-m-d H:i:s')),'id',$id);if(function_exists('simpan_log'))simpan_log('User '.$username.' update exception Factory Calendar day id '.$id,$username);fcj('good');break;
  case 'detail':
    $id=(int)fc_get('id');$h=$db->fetch("SELECT * FROM erp_factory_calendar_header WHERE id=? LIMIT 1",array($id));if(!$h){echo '<div class="alert alert-warning">Factory Calendar tidak ditemukan.</div>';break;}$days=$db->query("SELECT * FROM erp_factory_calendar WHERE calendar_id=? ORDER BY tanggal LIMIT 370",array($id));echo '<h3 style="margin-top:0">'.fch($h->calendar_code).' <small>'.fch($h->calendar_status).'</small></h3><div class="row"><div class="col-sm-3"><strong>Name</strong><br>'.fch($h->calendar_name).'</div><div class="col-sm-2"><strong>Plant</strong><br>'.fch($h->plant_code).'</div><div class="col-sm-3"><strong>Validity</strong><br>'.fch($h->valid_from.' s/d '.$h->valid_to).'</div><div class="col-sm-2"><strong>Shift</strong><br>'.fch($h->default_shift_code?:'-').'</div><div class="col-sm-2"><strong>Hours</strong><br>'.number_format((float)$h->working_hours,2,',','.').'</div></div><hr><div class="table-responsive"><table class="table table-bordered table-condensed"><thead><tr class="bg-gray"><th>Date</th><th>Day</th><th>Type</th><th>Shift</th><th class="text-right">Hours</th><th>Source</th><th>Remarks</th></tr></thead><tbody>';foreach($days as $d){$cls=$d->tipe_hari==='Kerja'?'success':($d->tipe_hari==='Khusus'?'warning':'danger');echo '<tr><td>'.fch($d->tanggal).'</td><td>'.fch($d->nama_hari).'</td><td><span class="label label-'.$cls.'">'.fch($d->tipe_hari).'</span></td><td>'.fch($d->shift_code).'</td><td class="text-right">'.number_format((float)$d->working_hours,2,',','.').'</td><td>'.fch($d->source_type).'</td><td>'.fch($d->keterangan).'</td></tr>';}echo '</tbody></table></div>';break;
  case 'excel':
    $initial=ob_get_level();ob_start();error_reporting(E_ALL & ~E_NOTICE & ~E_WARNING & ~E_DEPRECATED & ~E_USER_DEPRECATED);require_once "../../inc/lib/PHPExcel.php";require_once "../../inc/excel_style_helper.php";PHPExcel_Shared_File::setUseUploadTempDirectory(true);$f=fc_filters_get();$p=array();$w=fc_where($f,$p);$rows=$db->query("SELECT h.calendar_code,h.calendar_name,h.plant_code,h.valid_from,h.valid_to,h.default_shift_code,h.working_hours,h.calendar_status,d.tanggal,d.nama_hari,d.tipe_hari,d.shift_code,d.working_hours day_hours,d.source_type,d.keterangan FROM erp_factory_calendar_header h LEFT JOIN erp_factory_calendar d ON d.calendar_id=h.id $w ORDER BY h.calendar_code,d.tanggal",$p);$excel=new PHPExcel();$sheet=$excel->setActiveSheetIndex(0);$sheet->setTitle(erp_export_sheet_title('Factory Calendar'));$heads=array(erp_export_label("No"),erp_export_label("Calendar"),erp_export_label("Name"),erp_export_label("Plant"),erp_export_label("Valid From"),erp_export_label("Valid To"),erp_export_label("Default Shift"),erp_export_label("Header Hours"),erp_export_label("Status"),erp_export_label("Date"),erp_export_label("Day"),erp_export_label("Day Type"),erp_export_label("Shift"),erp_export_label("Day Hours"),erp_export_label("Source"),erp_export_label("Remarks"));foreach($heads as $i=>$v)$sheet->setCellValue(PHPExcel_Cell::stringFromColumnIndex($i).'4',$v);$r=5;$n=1;foreach($rows as $row){$vals=array($n++,$row->calendar_code,$row->calendar_name,$row->plant_code,$row->valid_from,$row->valid_to,$row->default_shift_code,(float)$row->working_hours,$row->calendar_status,$row->tanggal,$row->nama_hari,$row->tipe_hari,$row->shift_code,(float)$row->day_hours,$row->source_type,$row->keterangan);foreach($vals as $i=>$v)$sheet->setCellValue(PHPExcel_Cell::stringFromColumnIndex($i).$r,$v);$r++;}erpkb_excel_apply_standard_style($excel,array('sheet'=>$sheet,'title'=>erp_export_title('FACTORY CALENDAR REPORT - SAP PP'),'header_row'=>4,'first_data_row'=>5,'last_data_row'=>max(5,$r-1),'column_count'=>16,'numeric_columns'=>array('H','N'),'filters'=>array('Period'=>$f['from'].' s/d '.$f['to'],'Status'=>$f['status'],'Plant'=>$f['plant'],'Keyword'=>$f['keyword'])));$tmp=erpkb_excel_temp_file('factory_calendar_');PHPExcel_IOFactory::createWriter($excel,'Excel2007')->save($tmp);$size=@filesize($tmp);$sig=@file_get_contents($tmp,false,null,0,2);if(!$size||$sig!=='PK'){@unlink($tmp);while(ob_get_level()>$initial)ob_end_clean();header('Content-Type:text/plain; charset=utf-8');echo erp_t('export_excel_invalid_file','File Excel gagal dibuat dengan benar.');exit;}while(ob_get_level()>$initial)ob_end_clean();header('Content-Type: application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');header('Content-Disposition: attachment; filename="factory_calendar_'.date('Ymd_His').'.xlsx"');header('Content-Length: '.$size);header('Cache-Control: max-age=0');header('Pragma: public');readfile($tmp);@unlink($tmp);exit;
